import {{ Injectable }} from '@nestjs/common';
import {{ PostService }} from './models/post.model';
import {{ PostServiceRepository }} from './repositories/post.repository';

@Injectable()
export class PostServiceService {{
  constructor(
    private readonly repository: PostServiceRepository,
  ) {{}}

  async findAll(): Promise<PostService[]> {{
    return this.repository.findAll();
  }}

  async findById(id: string): Promise<PostService | null> {{
    return this.repository.findById(id);
  }}

  async create(data: Partial<PostService>): Promise<PostService> {{
    return this.repository.create(data);
  }}

  async update(id: string, data: Partial<PostService>): Promise<PostService> {{
    return this.repository.update(id, data);
  }}
}}

